import { generateDocument } from './api';

export const generateDoc = async (type, { userName, relationship, state, accountDetails, userId }) => {
    try {
        const payload = {
            type,
            userDetails: {
                user_name: userName,
                relationship: relationship,
                state: state,
                user_address: `Address in ${state}`,
                user_contact: '[User Contact]'
            },
            deceasedDetails: {
                deceased_name: '[Deceased Name]',
                date_of_death: '[Date of Death]'
            },
            accountDetails: accountDetails || {},
            userId
        };

        const response = await generateDocument(type, payload);

        // Create a blob link to download the PDF
        const url = window.URL.createObjectURL(new Blob([response.data], { type: 'application/pdf' }));
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', `${type.toUpperCase()}_Claim_Letter_Sahara.pdf`);
        document.body.appendChild(link);
        link.click();
        link.parentNode.removeChild(link);

    } catch (error) {
        console.error("Failed to generate document:", error);
        alert("Failed to generate document. Please try again.");
    }
};
